final:
module JK_latch (  
    input J,  
    input K,  
    input CLK,  
    output reg Q  
);  
  wire _tap_J = J & {1{1'b1}};

    always @(posedge CLK) begin  
        if (J && ~K)  
            Q <= 1;  // Set  
        else if (~J && K)  
            Q <= 0;  // Reset  
        else if (J && K)  
            Q <= ~Q; // Toggle  
    end  
endmodule
